scwin.f_GridToExcel = function() {
    if(ds_susRecvList.getRowCount() ==0) {
        $c.win.alert("선수금내역이 존재하지않습니다.");
        return false;
    }

    const options = {
            fileName : "선수금조회.xlsx" ,//[default : excel.xlsx] options.fileName 값이 없을 경우 default값 세팅
            sheetName : "선수금조회"
        };
    const infoArr = [];
    $c.data.downloadGridViewExcel(gr_susRecvList, options, infoArr);
};

